// Lấy dữ liệu từ 2 input
const input1 = $('getDocVu').all();
const input2 = $('getDocMKT').all();

let hasChanges = false;
let changes = [];

// Hàm tạo key từ các giá trị (bỏ qua row_number)
function createValueKey(record) {
  const values = [];
  Object.keys(record)
    .filter(key => key !== 'row_number')
    .sort()
    .forEach(key => {
      values.push(`${key}:${record[key]}`);
    });
  return values.join('|');
}

// Tạo Set các giá trị từ input1 và input2
const values1 = new Set(input1.map(item => createValueKey(item.json)));
const values2 = new Set(input2.map(item => createValueKey(item.json)));

// Kiểm tra số lượng bản ghi unique
if (values1.size !== values2.size) {
  hasChanges = true;
  changes.push({
    type: 'Unique record count difference',
    input1_unique: values1.size,
    input2_unique: values2.size
  });
}

// Tìm các giá trị chỉ có trong input1
values1.forEach(value => {
  if (!values2.has(value)) {
    hasChanges = true;
    changes.push({
      type: 'Only in Input 1',
      value: value
    });
  }
});

// Tìm các giá trị chỉ có trong input2
values2.forEach(value => {
  if (!values1.has(value)) {
    hasChanges = true;
    changes.push({
      type: 'Only in Input 2',
      value: value
    });
  }
});

// Trả về kết quả
return [{
  json: {
    has_changes: hasChanges,
    total_changes: changes.length,
    input1_records: input1.length,
    input2_records: input2.length,
    input1_unique: values1.size,
    input2_unique: values2.size,
    changes: changes.slice(0, 20) // Hiển thị 20 thay đổi đầu tiên
  }
}];
